# Load data from storage
users_2016 = locals()['var_functions.query_db:10']
reviews = locals()['var_functions.query_db:12']
businesses = locals()['var_functions.query_db:16']

# Step 1: Create set of 2016 user IDs
user_ids_2016 = set()
for user in users_2016:
    user_ids_2016.add(user['user_id'])

# Step 2: Filter reviews by 2016 users
filtered_reviews = []
for review in reviews:
    if review['user_id'] in user_ids_2016:
        filtered_reviews.append(review)

# Step 3: Build business mapping (businessid_X -> business data)
business_map = {}
for business in businesses:
    bus_id = business['business_id']
    if bus_id.startswith('businessid_'):
        clean_id = bus_id.replace('businessid_', '')
        business_map[clean_id] = business

# Step 4: Extract categories and count reviews
category_counts = Counter()
matched_count = 0

for review in filtered_reviews:
    business_ref = review['business_ref']
    if business_ref.startswith('businessref_'):
        clean_ref = business_ref.replace('businessref_', '')
        if clean_ref in business_map:
            matched_count += 1
            business = business_map[clean_ref]
            description = business.get('description', '')

            # Extract categories using simple pattern matching
            categories = []

            # Look for patterns like "services in X, Y, and Z"
            services_pos = description.lower().find('services in')
            if services_pos >= 0:
                # Extract text after "services in"
                after_services = description[services_pos + 11:]
                # Stop at period or newline
                end_pos = after_services.find('.')
                if end_pos < 0:
                    end_pos = after_services.find('\n')
                if end_pos >= 0:
                    after_services = after_services[:end_pos]

                # Split by comma and 'and'
                parts = after_services.split(',')
                for part in parts:
                    part = part.strip()
                    # Handle 'and' within a part
                    if ' and ' in part:
                        subparts = part.split(' and ')
                        for subpart in subparts:
                            subpart = subpart.strip().strip("'").strip('"').strip()
                            if len(subpart) > 2:
                                categories.append(subpart)
                    else:
                        part = part.strip().strip("'").strip('"').strip()
                        if len(part) > 2:
                            categories.append(part)

            # Alternative: look for "including" phrase
            if not categories:
                including_pos = description.lower().find('including')
