            end = len(desc)
        cat_text = desc[start:end]
    else:
        # Extract after location (third comma)
        loc_pos = desc.find('Located')
        if loc_pos >= 0:
            after_loc = desc[loc_pos:]
            commas = 0
            start_idx = 0
            for i, ch in enumerate(after_loc):
                if ch == ',':
                    commas += 1
                    if commas == 3:
                        start_idx = i + 1
                        break
            if start_idx > 0:
                cat_text = after_loc[start_idx:]
                # Cut at making/perfect/seeking
                for word in ['making', 'perfect', 'seeking']:
                    pos = cat_text.lower().find(word)
                    if pos > 0:
                        cat_text = cat_text[:pos]
                        break

    if cat_text:
        parts = []
        for sep in [',', ';', ' and ']:
            if sep in cat_text:
                parts = cat_text.split(sep)
                break
        if not parts:
            parts = [cat_text]

        for part in parts:
            cat = part.strip()
            cat = cat.strip("'").strip('"')
            cat = cat.rstrip('.').strip()
            cat = cat.replace('and ', '')
            if len(cat) > 2 and not cat.lower().startswith('this'):
                category_counts[cat] += 1

top_5 = category_counts.most_common(5)

result = {
    'users_2016': len(user_ids),
    'reviews_total': len(filtered_reviews),
    'reviews_matched': matched,
    'top_5_categories': top_5
}

